@props([
    'size' => 'md',
    'noBorder' => false,
    'bgNone' => false,
    'radiusNone' => false,
])

@php
    $sizes = [
        'none' => '',
        'sm' => 'h-8',
        'md' => 'h-9',
        'lg' => 'h-10',
        'xl' => 'h-11',
    ];

    $bg_class = ($bgNone ? '' : 'bg-bg') . '';

    $radius = $radiusNone ? '' : 'rounded-ui';
    $border_class = $noBorder ? 'border-transparent' : 'border border-border-input';
    $baseClasses = "ui-form-group-base ui-form-group ui-form-group-input relative flex {$radius} {$bg_class} {$border_class} text-fg";
    $sizeClasses = $sizes[$size] ?? $sizes['md'];

    $attributes = $attributes->class([$baseClasses, $sizeClasses])->merge([

    ]);
@endphp

<div {{ $attributes }}>
    {{ $slot }}
</div>

@props(['absolute' => false, 'class' => '', 'clickable' => false])

@php
    $isClickable = $clickable ? '' : 'pointer-events-none';
    $position = $absolute ? "absolute inset-y-0 pointer-events-none left-(--left-space,10px) {$isClickable}" : '';
    $final_class = "{$class} {$position} flex justify-center items-center";
@endphp
<span class="{{ $final_class }}">
    {{ $slot }}
</span>

@props(['absolute' => false, 'class' => '', 'clickable' => false])

@php
    $isClickable = $clickable ? '' : 'pointer-events-none';
    $position = $absolute ? "absolute inset-y-0 right-(--right-space,10px) {$clickable}" : '';
    $final_class = "{$class} {$position} flex justify-center items-center";
@endphp
<span class="{{ $final_class }}">
    {{ $slot }}
</span>
